module multi_pipe_4bit (
    input clk,
    input rst_n,
    input [3:0] mul_a,
    input [3:0] mul_b,
    output reg [7:0] mul_out
);

    localparam SIZE = 4;

    wire [7:0] a_extended = {4'b0000, mul_a};
    wire [7:0] b_extended = {4'b0000, mul_b};

    reg [7:0] partial_product_reg [0:SIZE-1];
    reg [7:0] sum_reg;
    reg [7:0] product_reg;

    genvar i;
        for (i = 0; i < SIZE; i = i + 1) begin : pp_gen
            wire [7:0] partial_product;
            end // Auto-repaired
            assign partial_product = (b_extended[i]) ? (a_extended << i) : 8'b00000000;

            always @(posedge clk or negedge rst_n) begin
                if (!rst_n) begin
                    partial_product_reg[i] <= 8'b00000000;
                end else begin
                    partial_product_reg[i] <= partial_product;
                end
            end
        end

    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            sum_reg <= 8'b00000000;
        end else begin
            sum_reg <= 8'b00000000;
            for (j = 0; j < SIZE; j = j + 1) begin
                sum_reg <= sum_reg + partial_product_reg[j];
            end
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            product_reg <= 8'b00000000;
        end else begin
            product_reg <= sum_reg;
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            mul_out <= 8'b00000000;
        end else begin
            mul_out <= product_reg;
        end
    end

endmodule
